import type { HTMLArkProps } from '@ark-ui/react/factory';
import { ark } from '@ark-ui/react/factory';
import { clsx } from 'clsx';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Separator.module.css';

type SeparatorProps = HTMLArkProps<'span'> & {
  orientation?: 'horizontal' | 'vertical';
  size?: 'xs' | 'sm' | 'md' | 'lg';
  variant?: 'solid' | 'dashed' | 'dotted';
};

const SeparatorRoot = forwardRef<HTMLSpanElement, SeparatorProps>(function SeparatorRoot(
  {
    asChild,
    className,
    orientation = 'horizontal',
    role,
    size = 'sm',
    variant = 'solid',
    'aria-orientation': ariaOrientation,
    ...props
  },
  ref,
) {
  const resolvedRole = role ?? 'separator';

  return (
    <ark.span
      ref={ref}
      asChild={asChild}
      role={resolvedRole}
      aria-orientation={ariaOrientation ?? (resolvedRole === 'separator' ? orientation : undefined)}
      data-scope="separator"
      data-part="root"
      data-slot="separator-root"
      data-orientation={orientation}
      data-size={size}
      data-variant={variant}
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const Separator = Object.assign(SeparatorRoot, {
  Root: SeparatorRoot,
});

export { Separator };

@layer ui.components {
  .root {
    display: block;
    flex-shrink: 0;
    border: 0;
    border-color: var(--separator-color, var(--color-border));
    border-style: var(--separator-border-style, var(--separator-variant-border-style, solid));

    &[data-size='xs'] {
      --separator-size-thickness: var(--separator-thickness-xs, 0.5px);
    }

    &[data-size='sm'] {
      --separator-size-thickness: var(--separator-thickness-sm, var(--border-width-sm));
    }

    &[data-size='md'] {
      --separator-size-thickness: var(--separator-thickness-md, var(--border-width-md));
    }

    &[data-size='lg'] {
      --separator-size-thickness: var(--separator-thickness-lg, 3px);
    }

    &[data-variant='dashed'] {
      --separator-variant-border-style: dashed;
    }

    &[data-variant='dotted'] {
      --separator-variant-border-style: dotted;
    }

    &[data-orientation='horizontal'] {
      width: var(--separator-length-horizontal, 100%);
      height: 0;
      border-block-start-width: var(
        --separator-thickness,
        var(--separator-size-thickness, var(--border-width-sm))
      );
    }

    &[data-orientation='vertical'] {
      width: 0;
      height: var(--separator-length-vertical, 1em);
      border-inline-start-width: var(
        --separator-thickness,
        var(--separator-size-thickness, var(--border-width-sm))
      );
    }
  }
}
